+    private abstract static class DeferredRunnable implements Runnable {
+        private boolean cancelled;
+
+        @Override
+        public final void run() {
+            if (!cancelled) {
+                action();
+            }
+
+            cleanup();
+        }
+
+        public final void cancel() {
+            cancelled = true;
+        }
+
+        protected abstract void action();
+        protected abstract void cleanup();
+    }

